import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

function makeHeaders(entries: Record<string, string>): Headers {
  const h = new Headers()
  for (const [key, value] of Object.entries(entries)) {
    h.set(key, value)
  }
  return h
}

// geo() with Vercel headers
{
  const headers = makeHeaders({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })
  const result = geo({ headers })
  assert.strictEqual(result.city, 'San Francisco', 'city should be San Francisco')
  assert.strictEqual(result.countryCode, 'US', 'countryCode should be US')
  assert.strictEqual(result.country, 'United States', 'country should be United States')
  assert.strictEqual(result.region, 'CA', 'region should be CA')
  assert.strictEqual(result.latitude, '37.7749', 'latitude should match')
  assert.strictEqual(result.longitude, '-122.4194', 'longitude should match')
  assert.strictEqual(result.timezone, 'America/Los_Angeles', 'timezone should match')
  console.log('PASS: geo() with Vercel headers')
}

// geoFromHeaders() with Cloudflare fallback for countryCode
{
  const headers = makeHeaders({
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'DE', 'countryCode should be DE from cf-ipcountry')
  assert.strictEqual(result.country, 'Germany', 'country should be Germany')
  assert.strictEqual(result.city, undefined, 'city should be undefined')
  console.log('PASS: geoFromHeaders() with Cloudflare fallback')
}

// Vercel header takes precedence over cf-ipcountry
{
  const headers = makeHeaders({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'FR', 'x-vercel-ip-country should take precedence')
  assert.strictEqual(result.country, 'France', 'country should be France')
  console.log('PASS: geoFromHeaders() Vercel header precedence over Cloudflare')
}

// Missing headers return undefined fields
{
  const headers = makeHeaders({})
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.city, undefined, 'city should be undefined')
  assert.strictEqual(result.country, undefined, 'country should be undefined')
  assert.strictEqual(result.countryCode, undefined, 'countryCode should be undefined')
  assert.strictEqual(result.region, undefined, 'region should be undefined')
  assert.strictEqual(result.latitude, undefined, 'latitude should be undefined')
  assert.strictEqual(result.longitude, undefined, 'longitude should be undefined')
  assert.strictEqual(result.timezone, undefined, 'timezone should be undefined')
  console.log('PASS: missing headers return undefined fields')
}

// Country name lookup from countryCode
{
  const testCases: Array<[string, string]> = [
    ['US', 'United States'],
    ['GB', 'United Kingdom'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['JP', 'Japan'],
    ['CN', 'China'],
    ['IN', 'India'],
    ['BR', 'Brazil'],
    ['AU', 'Australia'],
    ['CA', 'Canada'],
  ]
  for (const [code, name] of testCases) {
    const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': code }))
    assert.strictEqual(result.country, name, `country name for ${code} should be ${name}`)
  }
  console.log('PASS: country name lookup from countryCode')
}

// Unknown country code returns undefined country name
{
  const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': 'ZZ' }))
  assert.strictEqual(result.countryCode, 'ZZ', 'countryCode should be ZZ')
  assert.strictEqual(result.country, undefined, 'country should be undefined for unknown code')
  console.log('PASS: unknown countryCode returns undefined country name')
}

// isInRegion() with matching region
{
  const g = { countryCode: 'US', country: 'United States' }
  assert.strictEqual(isInRegion(g, ['US', 'CA', 'GB']), true, 'US should be in region list')
  console.log('PASS: isInRegion() with matching region')
}

// isInRegion() with non-matching region
{
  const g = { countryCode: 'DE', country: 'Germany' }
  assert.strictEqual(isInRegion(g, ['US', 'CA', 'GB']), false, 'DE should not be in region list')
  console.log('PASS: isInRegion() with non-matching region')
}

// isInRegion() case-insensitive comparison
{
  const g = { countryCode: 'us' }
  assert.strictEqual(isInRegion(g, ['US']), true, 'comparison should be case-insensitive')
  assert.strictEqual(isInRegion(g, ['us']), true, 'comparison should be case-insensitive (lowercase list)')
  console.log('PASS: isInRegion() case-insensitive comparison')
}

// isInRegion() with undefined countryCode
{
  const g = {}
  assert.strictEqual(isInRegion(g, ['US']), false, 'undefined countryCode should return false')
  console.log('PASS: isInRegion() with undefined countryCode')
}

// geoDistance() New York to London ~5570 km (allow 50 km tolerance)
{
  // New York: 40.7128° N, 74.0060° W
  // London:   51.5074° N, 0.1278° W
  const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(dist - 5570) <= 50,
    `New York to London distance should be ~5570 km, got ${dist.toFixed(1)} km`
  )
  console.log(`PASS: geoDistance() New York to London = ${dist.toFixed(1)} km`)
}

// geoDistance() same point returns 0
{
  const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
  assert.strictEqual(dist, 0, 'distance from a point to itself should be 0')
  console.log('PASS: geoDistance() same point returns 0')
}

// geoDistance() Sydney to Tokyo ~7823 km (allow 50 km tolerance)
{
  // Sydney: -33.8688° S, 151.2093° E
  // Tokyo:   35.6762° N, 139.6503° E
  const dist = geoDistance('-33.8688', '151.2093', '35.6762', '139.6503')
  assert.ok(
    Math.abs(dist - 7823) <= 50,
    `Sydney to Tokyo distance should be ~7823 km, got ${dist.toFixed(1)} km`
  )
  console.log(`PASS: geoDistance() Sydney to Tokyo = ${dist.toFixed(1)} km`)
}

console.log('\nAll geo tests passed.')

